return ['domain'=>NULL,'plural-forms'=>'nplurals=1; plural=0;','language'=>'ja','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'TranslatePress - Multilingual プラグインをバージョン %1$s 以上にアップデートしてください。%2$s が正しく機能するためです。','Please install and activate the TranslatePress - Multilingual plugin'=>'TranslatePress - Multilingual プラグインをインストールして有効化してください。','Install & Activate'=>'インストールして有効化','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'TranslatePress - Multilingual をバージョン %2$s 以上にアップデートしてください。現在インストールされている TranslatePress - Multilingual のバージョンは、現在の %1$s のバージョンと互換性がなくなりました。','All TranslatePress functionalities are disabled until then.'=>'それまで、TranslatePress のすべての機能は無効化されています。','Update Now'=>'今すぐアップデート','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'この TranslatePress アドオンはメインプラグインに統合されたため、使用されていません。削除できます。','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> を実行するには、PHP バージョン 5.6.20 以上が必要です。これは <a href="%s">最新の WordPress バージョンの最低要件</a> です。サーバー管理者に連絡して、PHP バージョンをアップデートしてください。','Advanced'=>'詳細設定','Settings saved.'=>'設定を保存しました。','Are you sure you want to remove this item?'=>'この項目を削除してもよろしいですか？','Remove'=>'削除','Add'=>'追加','Select...'=>'選択...','[%s] Low TranslatePress AI Words'=>'[%s] TranslatePress AI の残り単語数が少なくなっています','upgrade your plan or get extra AI Words'=>'プランをアップグレードするか、追加の AI 単語を取得してください','upgrade your plan'=>'プランをアップグレードする','TranslatePress AI words are running low on your site.'=>'サイトの TranslatePress AI 単語残数が少なくなっています。','Current status: %s words remaining'=>'現在の状況: 残り %s 単語','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'残りの AI 単語がなくなると、TranslatePress AI による自動翻訳は一時停止されます。','To continue translating your content, please %1$s over at %2$s'=>'コンテンツの翻訳を続けるには、%2$s で %1$s してください。','Manage Notification: %s'=>'通知の管理: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'%1$s の新しいバージョンが利用可能です。%2$sバージョン %3$s の詳細を表示%4$s、または %5$s今すぐ更新%6$s。','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'%1$s の新しいバージョンが利用可能です。%2$sバージョン %3$s の詳細を表示%4$s。','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'更新を有効にするには、%1$sライセンスキーを入力%2$sしてください。ライセンスキーが必要ですか？%3$s今すぐ購入%4$s。','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'更新を有効にするには、%1$sライセンスページ%2$sに移動して、有効なライセンスがあるか確認してください。','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'更新を有効にするには、ライセンスの更新が必要です。%1$sTranslatePress Account%2$sページに移動してログインし、更新してください。','You do not have permission to install plugin updates'=>'プラグインの更新をインストールする権限がありません','Error'=>'エラー','Your TranslatePress license key is invalid or missing.'=>'TranslatePress のライセンスキーが無効であるか、入力されていません。','Your license key expired on %s.'=>'ライセンスキーは %s に期限切れとなりました。','Your license key has been disabled.'=>'ライセンスキーは無効化されています。','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'この URL のライセンスキーは無効化されています。<a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites から再有効化してください。','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>ライセンスキーが一致しません。</strong>入力されたライセンスが、インストールされている TranslatePress のバージョンと一致しません。</p><p>TranslatePress Account から、ライセンスに対応する正しいバージョンがインストールされているか確認してください。</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'無料版プラグインのみがインストールされている状態で有料版のライセンスを追加した場合は、TranslatePress Account から有料版プラグインをインストールしてください。','Your license key has reached its activation limit.'=>'ライセンスキーのアクティベーション上限に達しました。','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'より多くのサイトを追加するにはプランをアップグレードしてください。%1$s今すぐアップグレード%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'このサイトはすでに無料ライセンスでアクティベートされています。各サイトで使用できる無料ライセンスは1つだけです。','An error occurred, please try again.'=>'エラーが発生しました。もう一度お試しください。','You have successfully activated your license'=>'ライセンスのアクティベーションが完了しました。','Others'=>'その他','Restrict by Language'=>'言語で制限','Exclude from Language'=>'言語から除外','Restrict element to language'=>'要素を言語に制限','Show this element only in one language.'=>'この要素を1つの言語でのみ表示する。','Enable translation'=>'翻訳を有効化','Allow translation to the corresponding language only if the content is written in the default language.'=>'コンテンツがデフォルトの言語で書かれている場合にのみ、対応する言語への翻訳を許可する。','Select language'=>'言語を選択','Choose in which language to show this element.'=>'この要素を表示する言語を選択してください。','Exclude element from language'=>'要素を言語から除外','Exclude this element from specific languages.'=>'この要素を特定の言語から除外する。','Select languages'=>'言語を選択','Choose from which languages to exclude this element.'=>'この要素を除外する言語を選択してください。','This element will still be visible when you are translating your website through the Translation Editor.'=>'翻訳エディターを使用してウェブサイトを翻訳しているときも、この要素は引き続き表示されます。','The content of this element should be written in the default language.'=>'この要素のコンテンツはデフォルトの言語で記述する必要があります。','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> で SQL エラーが発生しました。<a href="%s" title="View TranslatePress SQL Errors">エラーを確認</a>。','Automatic translation has been disabled.'=>'自動翻訳が無効化されました。','Dismiss this notice.'=>'この通知を閉じる。','Logged errors'=>'記録されたエラー','These are the most recent 5 errors logged by TranslatePress:'=>'TranslatePress が記録した最新の5件のエラー:','Yes'=>'はい','Why are these errors occuring'=>'これらのエラーが発生する理由','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'TranslatePress がデータベースへのクエリ実行時に異常を検出した場合、Google/DeepL による追加料金を防ぐため、自動翻訳機能を無効化することがあります。問題を解決した後、自動翻訳を手動で再度有効化する必要があります。','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'検出された SQL エラーは、テーブルが存在しない、SQL ユーザーにテーブル作成やその他の操作を行う権限がない、サイト移行後の問題、SQL サーバー設定の変更など、さまざまな理由で発生する可能性があります。','What you can do in this situation'=>'この状況でできること','Plan A.'=>'プランA.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'設定 -> TranslatePress -> 一般タブ に移動し、設定を保存してください。これにより、現在の SQL 設定を使用してテーブルが再生成されます。翻訳された言語でサイトを閲覧している間にエラーが発生しないか確認してください。古いエラーを表示していないことを確認するため、エラーのタイムスタンプを確認してください。最新のエラー 5 件のみが表示されます。','Plan B.'=>'プランB.','If your problem isn\'t solved, try the following steps:'=>'問題が解決しない場合は、以下の手順を試してください:','Create a backup of your database'=>'データベースのバックアップを作成する','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'エラーが発生している各翻訳テーブルのコピーを作成してください。同じデータベース内でテーブルをコピーできます（例: trp_dictionary_en_us_es_es_COPY）-- 現在の翻訳を保持したい場合のみ、この手順を実行してください。','Remove the trouble tables by executing the DROP function on them'=>'DROP 関数を実行して問題のあるテーブルを削除する','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'設定 -> TranslatePress -> 一般タブ に移動し、設定を保存してください。これにより、現在の SQL サーバーを使用してテーブルが再生成されます。','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'複製したテーブル（例: trp_dictionary_en_us_es_es_COPY）から、新しく生成されたテーブル（trp_dictionary_en_us_es_es）に該当する内容をコピーしてください -- 現在の翻訳を保持したい場合のみ、この手順を実行してください。','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'すべて正常に動作しているかテストしてください。問題が発生した場合は、最初の手順で作成したバックアップを復元できます。翻訳された言語でサイトを閲覧している間にエラーが発生しないか確認してください。古いエラーを表示していないことを確認するため、エラーのタイムスタンプを確認してください。最新のエラー 5 件のみが表示されます。','Plan C.'=>'プランC.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'問題がまだ解決しない場合は、ホスティング会社にエラーについて問い合わせてみてください。最も一般的な問題は、SQL ユーザーに Create Tables などの権限がないことです。','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'インストールできませんでした。<a href="%s" >プラグインダッシュボード</a>から再試行してください。','Active'=>'有効','Permission denied.'=>'権限がありません。','Invalid nonce.'=>'無効なnonceです。','Settings scope unknown.'=>'設定スコープが不明です。','Legacy disabled.'=>'レガシーは無効です。','Language Switcher'=>'言語スイッチャー','Change language to %s'=>'言語を%sに変更','Automatic Translation'=>'自動翻訳','DeepL'=>'DeepL','Unsupported languages'=>'未対応の言語','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'選択した自動翻訳エンジンはこれらの言語に対応していません。<br>翻訳エディターを使用して、これらの言語のページを手動で翻訳することもできます。','API key validation failed.'=>'APIキーの検証に失敗しました。','API key verification was successful.'=>'APIキーの検証に成功しました。','Please enter your Google Translate key.'=>'Google Translateのキーを入力してください。','Please enter your DeepL API key.'=>'DeepL APIキーを入力してください。','Not TranslatePress onboarding page.'=>'TranslatePressのオンボーディングページではありません。','Step %s does not exist'=>'ステップ%sは存在しません。','Welcome'=>'ようこそ','Add Languages'=>'言語を追加','Enable Addons'=>'アドオンを有効化','Finalize'=>'完了','Exit Setup'=>'セットアップを終了','Upgrade'=>'アップグレード','Nothing here'=>'ここには何もありません','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'<strong>TranslatePress</strong> のライセンスが見つからないか、無効です。<br/>TranslatePress AI による自動ウェブサイト翻訳、プレミアムアドオン、自動更新、サポートを有効にするには、%1$sコピーを登録%2$sしてください。ライセンスキーが必要ですか？%3$s今すぐ購入%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'<strong>TranslatePress</strong> のライセンスは %1$s に期限切れとなります。TranslatePress AI による自動翻訳、プレミアムアドオン、製品ダウンロード、自動更新へのアクセスを継続するには、%2$sライセンスを更新%3$sしてください。%4$s今すぐ更新%5$s','Error: '=>'エラー: ','Something went wrong, please try again.'=>'問題が発生しました。もう一度お試しください。','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'<strong>TranslatePress</strong> のライセンスは期限切れです。<br/>TranslatePress AI による自動翻訳、プレミアムアドオン、製品ダウンロード、自動更新へのアクセスを継続するには、%1$sライセンスを更新%2$sしてください。%3$s今すぐ更新 %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'ライセンスキーが一致しません。入力されたライセンスキーは、インストールされている <strong>%1$s</strong> バージョンと一致しません。<br/>%2$sTranslatePress アカウント%3$sから、ライセンスに適した正しいバージョンがインストールされているかご確認ください。','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>無料プラグインのみをインストールしているのに有料ライセンスを追加した場合は、TranslatePress アカウントから有料プラグインをインストールしてください。','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'<strong>%1$s</strong> ライセンスのアクティベーション上限に達しました。<br/>%2$sアカウント%3$sからアクティブなサイトを管理してください。','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'この URL でライセンスが無効化されています。<a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> サイトの管理 から再度有効化してください。','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'%1$s 自動翻訳にはアクティブなライセンスが必要です。ライセンスを%2$s更新%3$sするか、%4$sこちら%5$sから新規購入してください。','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'%3$s 自動翻訳を有効にするには、ライセンスキーを%1$s入力%2$sしてください。','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'TranslatePress AI の残り単語数が 5,000 語を下回っています。ウェブサイトの自動翻訳を継続するには、%sアカウントから追加の AI 単語を割引価格で購入%sしてください。',' Error: '=>' エラー: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'このウェブサイトはすでに無料ライセンスでアクティベート済みです。各ウェブサイトで使用できる無料ライセンスは 1 つだけです。より多くの TranslatePress AI 単語を取得するには、%1$sアカウント%2$sからプレミアムプランにアップグレードしてください。','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'<strong>TranslatePress</strong> の有効なライセンスがありません。TranslatePress AI にアクセスするには、%1$s無料で取得%2$sしてください。','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NEW:</strong> <strong>Different Domain per Language</strong> アドオンが登場しました。.de や .fr などの国別ドメインでグローバル SEO を強化し、ローカルな体験を作りましょう。<a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business または Developer</a> にアップグレードして、本アドオンとその他のプレミアム特典を利用しましょう！','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NEW:</strong> <strong>Different Domain per Language</strong> アドオンが登場しました。.de や .fr などの国別ドメインでグローバル SEO を強化し、ローカルな体験を作りましょう。<a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">詳細はこちら</a>。','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'1日の機械翻訳文字数上限を超過しました。詳細については、<strong>TranslatePress -> <a href="%s">自動翻訳</a></strong>ページをご確認ください。','Marketing optin'=>'マーケティングオプトイン','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'セキュリティおよび機能アップデートの通知、ならびに機密性の低い診断トラッキングにオプトインします。','TranslatePress Preferred User Language'=>'TranslatePress 優先ユーザー言語','Preferred language to navigate the site'=>'サイトナビゲーションの優先言語','The language is automatically set based by the last visited language by the user.'=>'言語は、ユーザーが最後に訪問した言語に基づいて自動的に設定されます。','Always use this language'=>'常にこの言語を使用する','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'この設定を有効にすると、優先言語は上記で選択した言語のままとなり、フロントエンドで変更されることはありません。<br>この言語は、ユーザーへのメール送信など、さまざまな操作で使用されます。','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'こんにちは！<strong>TranslatePress</strong> を使用してサイトを翻訳しておられるようですね。素晴らしいです！ ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'少しお時間をいただければ、WordPress.org での評価をお願いできれば幸いです（私のやる気も上がります）。','~ Razvan, developer of TranslatePress'=>'~ Razvan, TranslatePress の開発者','Rate TranslatePress on WordPress.org plugin page'=>'WordPress.org のプラグインページで TranslatePress を評価する','Ok, I will gladly help!'=>'はい、喜んで協力します！','No, thanks.'=>'いいえ、結構です。','Full Language Names'=>'完全な言語名','Short Language Names'=>'短縮言語名','Flags with Full Language Names'=>'国旗付き完全な言語名','Flags with Short Language Names'=>'国旗付き短縮言語名','Only Flags'=>'国旗のみ','Full Language Names No HTML'=>'完全な言語名（HTML なし）','Bottom Right'=>'右下','Bottom Left'=>'左下','Top Right'=>'右上','Top Left'=>'左上','Dark'=>'ダーク','Light'=>'ライト','Deactivate'=>'無効化','Activate'=>'有効化','Invalid language code. Please try again.'=>'言語コードが無効です。もう一度お試しください。','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'言語コードには A-Z a-z 0-9 - _ の文字のみ使用できます。TranslatePress の一般設定で言語コードを確認してください。','Error! Duplicate URL slug values.'=>'エラー！URL slug の値が重複しています。','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'同じ <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO コード</a> で異なるフォーマリティの言語を2つ選択することはできません。そうすると、重複した <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang タグ</a> が生成されるためです。','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'重複した言語が検出されました。<br>正確な翻訳管理のため、各言語は一度だけ追加できます。<br> 重複している言語の設定を変更して、もう一度お試しください。 ','Current Language'=>'現在の言語','Opposite Language'=>'反対の言語','General'=>'一般','Translate Site'=>'サイトを翻訳','Addons'=>'アドオン','License'=>'ライセンス','Settings'=>'設定','Activate License'=>'ライセンスを有効化','Pro Features'=>'Pro機能','Need Help?'=>'ヘルプが必要ですか？','Recent community discussions'=>'最近のコミュニティディスカッション','Loading...'=>'読み込み中...','Unable to load forum posts'=>'フォーラムの投稿を読み込めません。','Ask a Question'=>'質問する','View All Topics'=>'すべてのトピックを表示','by'=>'作成者','Have a question?'=>'質問はありますか？','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'プラグイン開発者から直接サポートを受けたり、改善を提案したり、フィードバックを共有したりできます！','Tip for faster help:'=>'迅速なサポートのためのヒント:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'試したこと、期待したこと、実際に起きたことを含めてください。スクリーンショットがあると助かります！','Toggle support chat'=>'サポートチャットの表示切替','Ask the community'=>'コミュニティに質問する','Close'=>'閉じる','Empty feed response'=>'フィードのレスポンスが空です','Unable to parse feed'=>'フィードを解析できませんでした','Just now'=>'たった今','%d hour ago'=>'%d時間前','%d day ago'=>'%d日前','Source'=>'ソース','Srcset'=>'srcset','Alt attribute'=>'alt 属性','Title attribute'=>'title 属性','Anchor link'=>'アンカーリンク','Placeholder attribute'=>'placeholder 属性','Submit attribute'=>'submit 属性','Text'=>'テキスト','Video Poster'=>'動画ポスター','plural form'=>'複数形','one'=>'単数','few'=>'少数','many'=>'多数','other'=>'その他','Saved'=>'保存しました','Save'=>'保存','Saving translation...'=>'翻訳を保存中...','You have unsaved changes!'=>'保存されていない変更があります!','Discard changes'=>'変更を破棄','Discard All'=>'すべて破棄','Loading Strings...'=>'文字列を読み込んでいます…','Select string to translate...'=>'翻訳する文字列を選択…','Close Editor'=>'エディターを閉じる','From'=>'原文','To'=>'訳文','Add Media'=>'メディアを追加','Other languages'=>'他の言語','Context'=>'コンテキスト','View Website As'=>'表示言語','Available in our Pro Versions'=>'Pro版で利用可能','Select or Upload Media'=>'メディアを選択またはアップロード','Use this media'=>'このメディアを使用','Translate'=>'翻訳','Translate entire block element'=>'ブロック全体を翻訳','Split block to translate strings individually'=>'ブロックを分割して文字列を個別に翻訳','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'翻訳の変更を保存する。ショートカット: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'ドロップダウンリストの次の文字列に移動します。ショートカット: CTRL(⌘) + ALT + 右矢印','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'ドロップダウンリストの前の文字列に移動します。ショートカット: CTRL(⌘) + ALT + 左矢印','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'すべての変更を破棄する。ショートカット: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'このテキストボックスの変更を破棄する。すべてのテキストボックスの変更を破棄するには、ショートカット CTRL(⌘) + ALT + Z を使用する。','Dismiss tooltip'=>'ツールチップを閉じる','Quick Intro'=>'クイック紹介','Are you sure you want to split this phrase into smaller parts?'=>'このフレーズをより小さい部分に分割してもよろしいですか？','This string is not ready for translation yet. <br>Try again in a moment...'=>'この文字列はまだ翻訳の準備ができていません。<br>しばらくしてから再試行してください…','For this option to work, please update the Browse as other role add-on to the latest version.'=>'このオプションを使用するには、「Browse as other role」アドオンを最新バージョンに更新してください。','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'slug を翻訳するには、SEO Pack アドオンを最新バージョンにアップデートしてください。','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'<a href="%s">設定→TranslatePress</a>から新しい言語を追加できます。','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'ただし、TranslatePress を使用してページ内の <strong style="background: #f5fb9d;">gettext 文字列を変更</strong>することは引き続き可能です。','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'ユーザーが作成した文字列は変更できません。テーマとプラグインの文字列のみ変更可能です。','Extra Translation Features'=>'追加の翻訳機能','Support for 130+ Extra Languages'=>'130以上の追加言語に対応','Access to TranslatePress AI'=>'TranslatePress AIへのアクセス','Translate SEO Title, Description, Slug'=>'SEO タイトル、説明、slug の翻訳','Publish only when translation is complete'=>'翻訳が完了した場合のみ公開する','Translate by Browsing as User Role'=>'ユーザーロールとして閲覧して翻訳','Different Menu Items for each Language'=>'言語ごとに異なるメニュー項目','Automatic User Language Detection'=>'ユーザーの言語を自動検出','Upgrade to PRO'=>'PROにアップグレード','Upgrade to PRO with our biggest discount of the year!'=>'今年最大の割引でPROにアップグレードしましょう！','This Black Friday, get access to these features and more at a fraction of the costs:'=>'今回のブラックフライデーには、これらの機能などを通常よりお得な価格でご利用いただけます:','No available suggestions'=>'利用可能な候補はありません','Suggestions from translation memory'=>'翻訳メモリからの候補','Click to Copy'=>'クリックしてコピー','Human Translation'=>'人工翻訳','Machine Translation'=>'機械翻訳','Text on this page is %s% translated into all languages.'=>'このページのテキストはすべての言語に%s%翻訳されています。','%1$s% of text on this page is translated into %2$s.'=>'このページのテキストの%1$s%が%2$sに翻訳されています。','This page is %1$s% translated into %2$s.'=>'このページは%2$sに%1$s%翻訳されています。','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'編集しようとしている slug は他の slug タイプにも存在します: %s. 現在のタイプに関わらず、編集すると各出現箇所が置き換えられます。','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'ページ上のテキストにマウスを合わせ、%sをクリックし、<br>サイドバーで翻訳を修正してください。','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'翻訳の保存を忘れないでください。キーボードショートカット CTRL(⌘) + S を使用してください。','Switch language to see the translation changes directly on the page.'=>'言語を切り替えると、ページ上で翻訳の変更を直接確認できます。','Search for any text in this page in the dropdown.'=>'ドロップダウンでこのページ内のテキストを検索してください。','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'%sライセンスは<span class="trp-license-status-emphasized">期限切れ</span>です。','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'ライセンスを更新して、TranslatePress AI、プレミアムアドオン、自動更新、サポートへの継続的なアクセスを維持してください。','Renew Now'=>'今すぐ更新','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>今回のブラックフライデーに、特別価格でライセンスを更新</strong>して、製品ダウンロード、自動更新、サポートへの継続的なアクセスを維持してください。','Get Deal'=>'特典を受ける','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'%sライセンスは<span class="trp-license-status-emphasized">返金されました</span>。','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'新しいライセンスを購入して、TranslatePress AI、プレミアムアドオン、自動更新、サポートへの継続的なアクセスを維持してください。','Purchase a new license'=>'新規ライセンスを購入','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'お使いの%sライセンスは<span class="trp-license-status-emphasized">未登録または無効</span>です。','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'有効なライセンスを入力して、TranslatePress AI、プレミアムアドオン、自動更新、サポートにアクセスしてください。ライセンスキーが必要ですか？%1$s今すぐ購入%2$s','Enter a valid license'=>'有効なライセンスを入力','Slugs'=>'slug','Meta Information'=>'メタ情報','String List'=>'文字列リスト','Gettext Strings'=>'Gettext 文字列','Images'=>'画像','Videos'=>'動画','Audios'=>'音声','Dynamically Added Strings'=>'動的に追加された文字列','Translation Editor'=>'翻訳エディター','Edit translations by visually selecting them on each site page'=>'各サイトページで翻訳を視覚的に選択して編集する','String Translation'=>'文字列の翻訳','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'URL slug、プラグイン、テーマの翻訳（メール、フォームなど）を編集','Current User'=>'現在のユーザー','Logged Out'=>'ログアウト済み','Translate Page'=>'ページを翻訳','Add a New Language'=>'新しい言語を追加','Get a Free AI License'=>'無料のAIライセンスを取得','Your License is Invalid'=>'ライセンスが無効です','Get More AI Words (%d left)'=>'AIワードを追加取得（残り%d語）','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'翻訳エディターで投稿を開きます。事前に下書きとして保存するか、公開しておく必要があります。','Security check'=>'セキュリティチェック','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>警告:</strong> 一部の文字列に正しくエンコードされていない文字が含まれている可能性があります。これによりクエリが破損し、ライブモードでページが未翻訳のまま表示される可能性があります。以下の文字列またはその出力方法を見直してください。','TranslatePress data update'=>'TranslatePressデータの更新','We need to update your translations database to the latest version.'=>'翻訳データベースを最新バージョンに更新する必要があります。','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'更新すると、プラグインとテーマのローカライズされたテキストの翻訳を編集できるようになります。既存の翻訳はこれまで通り動作します。','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'重要: まずデータベースのバックアップを取ることを強く推奨します！\\n続行してもよろしいですか？','Run the updater'=>'アップデーターを実行','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'更新すると、スラッグの翻訳を編集できるようになります。既存の翻訳は引き続き正常に動作します。','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'SEOアドオンを<br/>WordPress -> 設定 -> TranslatePress -> アドオンセクションから有効化してください','Go to Addons'=>'アドオンへ移動','The SEO Pack add-on allows translation of all the URL slugs:'=>'SEO Pack アドオンでは、すべての URL スラッグを翻訳できます:','Taxonomy slugs'=>'タクソノミースラッグ','Term slugs'=>'タームスラッグ','Post slugs (this includes pages and custom post types)'=>'投稿スラッグ（ページやカスタム投稿タイプも含む）','Post type base slugs'=>'投稿タイプベーススラッグ','WooCommerce slugs'=>'WooCommerce スラッグ','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'SEO Pack アドオンは、このプラグインのすべてのプレミアム版で利用できます。','Upgrade to Pro'=>'Pro 版にアップグレード','Description'=>'説明','Article Section'=>'記事セクション','Article Tag'=>'記事タグ','OG Title'=>'OG タイトル','OG Site Name'=>'OG サイト名','OG Description'=>'OG 説明','OG Image Alt'=>'OG 画像の代替テキスト','Twitter Title'=>'Twitter タイトル','Twitter Description'=>'Twitter 説明','Twitter Image Alt'=>'Twitter 画像の代替テキスト','Page Title'=>'ページタイトル','Dublin Core Title'=>'Dublin Core タイトル','Dublin Core Description'=>'Dublin Core 説明','OG Image'=>'OG 画像','OG Image Secure URL'=>'OG 画像の Secure URL','Twitter Image'=>'Twitter 画像','Removing cdata dictionary strings for language %s...'=>'言語 %s の CDATA 辞書文字列を削除中...','Removing untranslated dictionary links for language %s...'=>'言語 %s の未翻訳辞書リンクを削除中...','Removing duplicated gettext strings for language %s...'=>'言語 %s の重複した gettext 文字列を削除中...','Removing duplicated dictionary strings for language %s...'=>'言語 %s の重複した辞書文字列を削除中...','Removing untranslated dictionary strings where translation is available for language %s...'=>'言語 %s で翻訳が利用可能な未翻訳の辞書文字列を削除中...','Inserting original strings for language %s...'=>'言語 %s の原文文字列を挿入中...','Cleaning original strings table for language %s...'=>'言語 %s の原文文字列テーブルをクリーンアップ中...','Updating original string ids for language %s...'=>'言語 %s の原文文字列 ID を更新中...','Regenerating original meta table for language %s...'=>'言語 %s の原文メタテーブルを再生成中...','Cleaning original meta table for language %s...'=>'言語 %s の原文メタテーブルをクリーニング中...','Replacing original id NULL with value for language %s...'=>'言語 %s の原文 ID の NULL を値に置換中...','Inserting gettext original strings for language %s...'=>'言語 %s の gettext 原文文字列を挿入中...','Cleaning gettext original strings table for language %s...'=>'言語 %s の gettext 原文文字列テーブルをクリーンアップ中...','Updating gettext original string ids for language %s...'=>'言語 %s の gettext 原文文字列 ID を更新中...','Migrating taxonomy and post type base slugs to new table structure...'=>'タクソノミーおよび投稿タイプベーススラッグを新しいテーブル構造に移行中...','Migrating post slugs to new table structure for language %s...'=>'言語 %s の投稿スラッグを新しいテーブル構造に移行中...','Migrating term slugs to new table structure for language %s...'=>'言語 %s のターム slug を新しいテーブル構造に移行しています...','Finishing up...'=>'完了処理中...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'データベースの最適化が正常に完了しませんでした。元のデータベースを復元するか、<a href="%s" >もう一度お試しください。</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'更新を中止しました。お使いのユーザーアカウントにはデータベースの更新を実行する権限がありません。','Update aborted! Invalid nonce.'=>'更新を中止しました。無効な nonce です。','Update aborted! Incorrect action.'=>'更新を中止しました。不正なアクションです。','Update aborted! Incorrect language code.'=>'更新を中止しました。言語コードが正しくありません。','Updating database to version %s+'=>'データベースをバージョン %s+ に更新中','Processing table for language %s...'=>'言語 %s のテーブルを処理中...','Back to TranslatePress Settings'=>'TranslatePress 設定に戻る','Successfully updated database!'=>'データベースの更新が完了しました。',' done.'=>' 完了。','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'すべての個別の TranslatePress アドオンプラグインは<a href="%1$s" target="_blank">提供終了</a>となり、現在は TranslatePress のプレミアム Personal、Business、Developer バージョンに含まれています。<a href="%2$s" target="_blank">アカウントページ</a>にログインして、新しいプレミアムバージョンをダウンロードし、インストールしてください。個別アドオンの設定は引き継がれます。','Brand-new Language Switcher Settings are here!'=>'まったく新しい言語スイッチャー設定が登場しました！','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'あらかじめ用意されたテンプレートを確認したり、色、フラグスタイル、間隔、レイアウトなどを切り替えたりできます。ライブプレビューを使用して、数秒でスイッチャーを完璧に仕上げましょう。','Start customizing'=>'カスタマイズを開始','Read documentation'=>'ドキュメントを参照','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> は <strong><a href="http://php.net/manual/en/book.mbstring.php">マルチバイト文字列 PHP ライブラリ</a></strong> を必要とします。サーバー管理者に連絡して、サーバーへのインストールを依頼してください。','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'WPEngine ホスティングで長いクエリの制限が検出されました。一部の大きなページが翻訳されていないように表示される場合があります。サイトの wp-config.php に以下を追加することで制限を解除できます: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'カスタム言語フラグ','The Language code of the added custom language cannot be empty.'=>'追加されたカスタム言語の言語コードは空にできません。','The Language code of the added custom language is invalid.'=>'追加されたカスタム言語の言語コードが無効です。','The Automatic Translation Code of the added custom language is invalid.'=>'追加されたカスタム言語の自動翻訳コードが無効です。','TranslatePress Add-ons'=>'TranslatePress アドオン','You must first purchase this version to have access to the addon %1$shere%2$s'=>'アドオンにアクセスするには、まずこのバージョンを%1$sこちら%2$sで購入する必要があります。','Please %1$senter your license%2$s key first, to activate this addon.'=>'このアドオンを有効化するには、まず%1$sライセンスキーを入力%2$sしてください。','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'このアドオンにアクセスするには有効なライセンスが必要です。新規購入または更新は%1$sこちら%2$sから行えます。','Advanced Add-ons'=>'高度なアドオン','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'これらのアドオンは翻訳プラグインの機能を拡張し、Developer、Business、Personal プランで利用できます。','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack（レガシー）','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'ページ slug、ページタイトル、ディスクリプション、および Facebook と Twitter のソーシャルグラフ情報の SEO 対応。HTML の lang 属性が適切に設定されます。','Multiple Languages'=>'複数言語','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'プロジェクトをグローバル展開するために必要な数の言語を追加できます。すべての翻訳が完了してから言語を公開してください。','Pro Add-ons'=>'Pro アドオン','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'これらのアドオンは翻訳プラグインの機能を拡張し、Business、Developer プランで利用できます。','DeepL Automatic Translation'=>'DeepL 自動翻訳','Automatically translate your website through the DeepL API.'=>'DeepL API を使用してウェブサイトを自動翻訳します。','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'ブラウザ設定または IP アドレスに基づいて訪問者に優先言語への切り替えを促し、最後に訪問した言語を記憶します。','Translator Accounts'=>'翻訳者アカウント','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'新規ユーザー用に翻訳者アカウントを作成するか、管理者以外の既存ユーザーにウェブサイトの翻訳を許可します。','Browse As User Role'=>'ユーザーロールとして閲覧','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'特定のユーザーロールと同じようにウェブサイトを閲覧できます。特定のユーザーに表示される動的コンテンツや非表示コンテンツの確認に非常に便利です。','Navigation Based on Language'=>'言語に基づくナビゲーション','Configure different menu items for different languages.'=>'言語ごとに異なるメニュー項目を設定できます。','Different Domain per Language'=>'言語ごとに異なるドメイン','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'翻訳された各バージョンに別々のドメインまたはサブドメインを接続します。ブランドのローカルアイデンティティを強化し、サポートするすべての言語のSEOパフォーマンスを向上させます。','Recommended Plugins'=>'おすすめのプラグイン','A short list of plugins you can use to extend your website.'=>'サイトを拡張するために使用できるプラグインの簡易リストです。','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Profile Builder のカスタムユーザープロフィールフィールドを使用して、登録フォームでより多くのユーザー情報を取得したり、メール確認プロセスを追加して顧客のアカウントを確認したりできます。','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'ユーザーの支払いを受け付け、サブスクリプションプランを作成し、メンバーシップサイトのコンテンツを制限します。','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'WordPress サイトでノーコードの自動化とワークフローを作成します。プラグイン、サイト、アプリを簡単に連携させます。','Save Changes'=>'変更を保存','TranslatePress Errors'=>'TranslatePress のエラー','There are no logged errors.'=>'ログに記録されたエラーはありません。','Change language'=>'言語を変更','Website language selector'=>'サイトの言語セレクター','WordPress Translation Plugin'=>'WordPress 翻訳プラグイン','Available languages'=>'利用可能な言語','Language Switcher update notice'=>'言語切り替えの更新通知','Legacy language switcher is currently enabled'=>'従来の言語切り替えが現在有効になっています','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'スイッチャーをアップグレードし、より豊かなカスタマイズと優れたユーザーエクスペリエンスを実現しました。<br>新しい設定ツールを使用するには、<strong>従来の言語切り替えを読み込む</strong>をオフにしてください。','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'注: <strong>詳細設定 → <a href="%s">トラブルシューティング</a></strong> からいつでも元に戻すことができます。','Enable the new switcher'=>'新しいスイッチャーを有効にする','Your License Key is valid.'=>'ライセンスキーは有効です。','Your License Key is invalid.'=>'ライセンスキーは無効です。','Your License has expired.'=>'ライセンスの有効期限が切れました。','Deactivate License'=>'ライセンスを無効化','Add a license key'=>'ライセンスキーを追加','License Key'=>'ライセンスキー','Manage your license in your %1$s.'=>'%1$sでライセンスを管理してください。','Account Page'=>'アカウントページ','Don’t have a TranslatePress AI License Key?'=>'TranslatePress AI のライセンスキーをお持ちではありませんか？','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'無料アカウントを作成すれば、%1$s無料%2$sで取得できます。含まれるもの:','Access to TranslatePress AI for instant automatic translations'=>'TranslatePress AI による即時自動翻訳へのアクセス','2000 AI words to translate automatically'=>'自動翻訳用 AI ワード 2000 語','Get a free License Today'=>'今すぐ無料ライセンスを取得','Debug Information'=>'デバッグ情報','Debug Data for License Checking'=>'ライセンス確認用デバッグデータ','Debug Data for License Activation'=>'ライセンス有効化用デバッグデータ','Get more AI words and unlock all features with TranslatePress Pro.'=>'TranslatePress Pro でより多くの AI ワードを取得し、すべての機能をアンロックしましょう。','Upgrade now ↗'=>'今すぐアップグレード ↗','Already purchased a Premium version?'=>'すでにプレミアム版をお持ちですか？','Go to your %1$s'=>'%1$sに移動','TranslatePress.com Account'=>'TranslatePress.com アカウント','Download & Install the Pro plugin'=>'Pro プラグインをダウンロードしてインストール','Learn More'=>'詳細','Get a translation volume estimate with a detailed breakdown per page'=>'ページごとの詳細な内訳付きで翻訳量の見積もりを取得する','Find how many translatable words are on your website'=>'サイト内の翻訳可能な単語数を確認する','Enable Automatic Translation'=>'自動翻訳を有効にする','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'自動翻訳に<strong>DeepL</strong>を使用するには、<a href="%1$s" target="_self" title="%2$s">%2$s</a>からこの Pro アドオンを有効化してください。','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'<strong>DeepL</strong>による自動翻訳は、<a href="%1$s" target="_blank" title="%2$s">%2$s</a>としてご利用いただけます。','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'アップグレードすると、すべての有料アドオンやプレミアムサポートにアクセスできるほか、TranslatePress の将来の開発資金にも協力できます。','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'DeepL API の使用料は別途必要です。<a href="https://www.deepl.com/pro.html#developer">DeepL の料金情報</a>をご確認ください。','TranslatePress Pro Add-ons'=>'TranslatePress Pro アドオン','Test API credentials'=>'API 認証情報をテスト','Check if the selected translation engine is configured correctly.'=>'選択した翻訳エンジンが正しく設定されているかどうかを確認します。','Alternative Engines'=>'代替エンジン','Switch to TranslatePress AI'=>'TranslatePress AI に切り替える','Integrate machine translation directly with your WordPress website.'=>'機械翻訳を WordPress サイトに直接統合します。','More info'=>'詳細情報','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Web サイトを自動翻訳するために使用するエンジンを%1$s選択してください。','Automatic Translation Settings'=>'自動翻訳設定','AI Words Low Notification'=>'AIワード数不足通知','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'TranslatePress AIのワード数が指定したしきい値を下回った場合にメールで通知します。','This feature is only available when using the TranslatePress AI translation engine.'=>'この機能は、TranslatePress AI翻訳エンジンを使用している場合にのみ利用できます。','Notification Email'=>'通知メールアドレス','The email address where the low AI words notification will be sent.'=>'AIワード数不足通知を送信するメールアドレスです。','Word Threshold'=>'ワード数しきい値','words'=>'ワード','You will be notified when remaining AI words drop below this number.'=>'残りのAIワード数がこの数値を下回ったときに通知されます。','Automatically Translate Slugs'=>'slug の自動翻訳','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'投稿、固定ページ、カスタム投稿タイプの slug の自動翻訳を生成します。<br/>slug は各ページの2回目の更新から自動翻訳されます。','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'この機能は有料版でのみ利用できます。TranslatePressをアップグレードして、さらに多くのプレミアム機能をアンロックしましょう。','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'<a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Packアドオン</a>のインストールと有効化が必要です。','Upgrade now'=>'今すぐアップグレード','Block Crawlers'=>'クローラーのブロック','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'ウェブサイト上で自動翻訳をトリガーするクローラーをブロックします。<br>これにより、クローラーがこのサイトのページにアクセスすることを妨げるものではありません。','Limit machine translation / characters per day'=>'機械翻訳の1日あたり文字数制限','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'自動翻訳される文字数に上限を設けることで、プロジェクトの予算をより適切に管理できます。','characters per day'=>'1日あたりの文字数','Today\'s Character Count: '=>'本日の文字数: ','Log machine translation queries.'=>'機械翻訳クエリをログに記録する。','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'テスト目的でのみ有効にしてください。パフォーマンスに影響を与える可能性があります。<br>すべての記録は wp_trp_machine_translation_log データベーステーブルに保存されます。<a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> のようなプラグインを使用してログを参照するか、データベース管理ツール（PHPMyAdmin など）から直接アクセスしてください。','Test API Credentials'=>'API認証情報をテスト','HTTP Referrer: '=>'HTTP リファラー: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'APIのダッシュボードでキーの使用を制限できる場合、このHTTPリファラーを使用してください。','Response'=>'レスポンス','Response Body'=>'レスポンス本文','Entire Response From wp_remote_get():'=>'wp_remote_get() からの完全なレスポンス:','All Languages'=>'すべての言語','Select the languages you wish to make your website available in.'=>'ウェブサイトで利用可能にする言語を選択してください。','Formality'=>'フォーマリティ','Code'=>'コード','Slug'=>'slug','Default'=>'デフォルト','Formal'=>'フォーマル','Informal'=>'インフォーマル','Language'=>'言語','This language does not support formality. '=>'この言語はフォーマリティをサポートしていません。','Are you sure you want to remove this language?'=>'この言語を削除してもよろしいですか？','Custom Languages'=>'カスタム言語','To Add more languages activate the Multiple Languages Addon'=>'さらに言語を追加するには、Multiple Languages アドオンを有効化してください。','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'さらに言語を追加するには有効なライセンスが必要です。%1$sアカウント%2$sでライセンスが有効であることを確認してください。','Please %1$senter your license%2$s key first to add more languages.'=>'さらに言語を追加するには、まず %1$sライセンスキーを入力%2$sしてください。','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'2言語以上の追加は有料機能です。TranslatePress をアップグレードして、より多くのプレミアム機能をアンロックしてください。','Website Languages'=>'サイトの言語','Default Language'=>'デフォルト言語','Select the language your content is written in.'=>'コンテンツが書かれている言語を選択してください。','WARNING. Changing the default language will invalidate existing translations.'=>'警告。デフォルト言語を変更すると、既存の翻訳が無効になります。','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'en_US から en_GB に変更する場合も同様です。これらは2つの異なる言語として扱われるためです。','In most cases changing the default flag is all it is needed: '=>'ほとんどの場合、デフォルトのフラグを変更するだけで十分です: ','replace the default flag'=>'デフォルトのフラグを置き換える','Re-run Setup Wizard'=>'セットアップウィザードを再実行','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'セットアップウィザードを使用すると、TranslatePress をすばやくセットアップできます。いつでも開始できます。','Language Settings'=>'言語設定','Use Native language name'=>'ネイティブの言語名を使用する','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'言語名をネイティブ表記で表示する場合はチェックしてください。チェックを外すと、英語で表示されます。','Use a subdirectory for the default language'=>'デフォルト言語にサブディレクトリを使用する','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'デフォルト言語の URL にサブディレクトリを追加する場合はチェックしてください。</br>このオプションをチェックすると、サイト訪問者に表示されるデフォルト言語は「すべての言語」リストの最初の言語になります。','Force language in custom links'=>'カスタムリンクで言語を強制する','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'言語エンコーディングなしのカスタムリンクでも現在選択されている言語を維持するよう強制する場合は「はい」を選択してください。','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'任意のページやウィジェットでshortcodeを使用してください。','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'WP Gutenbergエディターで<a href="%s" title="Language Switcher Block Documentation">言語切り替えブロック</a>を追加することもできます。','Menu item'=>'メニュー項目','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'%1$s外観 -> メニュー%2$sに移動して、任意のメニューの言語切り替えに言語を追加してください。','Learn more in our documentation.'=>'詳細はドキュメントをご覧ください。','Floating language selection'=>'フローティング言語選択','Add a floating dropdown that follows the user on every page.'=>'すべてのページでユーザーに追従するフローティングドロップダウンを追加します。','Show "Powered by TranslatePress"'=>'「Powered by TranslatePress」を表示','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'フローティング言語切り替えに「Powered by TranslatePress」の小さなラベルを表示します。','5 Days to Better Multilingual Websites'=>'より良い多言語サイトへの5日間','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%s無料の特別なオンボーディングコースに参加%sして、多言語トラフィックを拡大し、国際市場にリーチし、時間とコストを節約しながら、TranslatePressを最大限に活用する方法を学びましょう！','Invalid email address'=>'メールアドレスが無効です','Your email'=>'メールアドレス','Sign me up!'=>'登録する！','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'メールアドレスで登録して、5部構成のメールガイドを受け取り、TranslatePressの機能を最大限に活用しましょう。','Dismiss email course notification'=>'メールコースの通知を閉じる','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'%sさん、<br>重要なアップデートを見逃さないよう、セキュリティおよび機能アップデートの通知と非機密性の診断トラッキングをオプトインしてください。','Allow & Continue'=>'許可して続行','Skip'=>'スキップ','This will allow TranslatePress to:'=>'TranslatePressに以下の許可を与えます:','Your profile overview'=>'プロフィールの概要','Name and email address'=>'名前とメールアドレス','Admin Notices'=>'管理画面通知','Updates, announcements, marketing, no spam'=>'アップデート、アナウンス、マーケティング、スパムなし','Plugin status & settings'=>'プラグインの状態と設定','Active, Deactivated, installed version and settings'=>'有効、無効、インストール済みバージョン、設定','Privacy Policy'=>'プライバシーポリシー','Terms of Service'=>'利用規約','Support'=>'サポート','Documentation'=>'ドキュメント','Add Extra AI Words'=>'AIワードを追加','Optimize TranslatePress database tables'=>'TranslatePressのデータベーステーブルを最適化','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>重要な注意:</strong> この操作を実行する前に、必ずデータベースのバックアップを作成することを強く推奨します。','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'重要: 必ずデータベースのバックアップを作成してから実行することを強く推奨します！！続行してもよろしいですか？','Operations to perform'=>'実行する操作','Remove CDATA for original and dictionary strings'=>'オリジナル文字列と辞書文字列の CDATA を削除','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'trp_original_stringsテーブルおよびtrp_dictionary_*テーブルからCDATAを削除します。<br>この種のコンテンツはTranslatePressによって検出されるべきではありません。プラグインの旧バージョンによりデータベースに混入した可能性があります。','Remove untranslated links from dictionary tables'=>'辞書テーブルから未翻訳のリンクを削除','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'すべての trp_dictionary_* テーブルから未翻訳のリンクと画像を削除します。これらのテーブルには、投稿コンテンツ、投稿タイトル、メニューなどのユーザー入力文字列の翻訳が含まれています。','Remove duplicate rows for gettext strings'=>'gettext 文字列の重複行を削除','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'すべての trp_gettext_* テーブルから重複行を削除します。これらのテーブルには、テーマおよびプラグインの文字列の翻訳が含まれています。','Remove duplicate rows for dictionary strings'=>'辞書文字列の重複行を削除','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'すべての trp_dictionary_* テーブルから重複行を削除します。これらのテーブルには、投稿コンテンツ、投稿タイトル、メニューなどのユーザー入力文字列の翻訳が含まれています。','Remove duplicate rows for original dictionary strings'=>'オリジナル辞書文字列の重複行を削除','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'trp_original_strings テーブルの重複行を削除します。このテーブルには、デフォルト言語の文字列が翻訳なしで含まれています。<br>trp_original_meta テーブル（投稿の親 ID を参照するメタ情報を含む）も再生成されます。<br>このような重複は、予期しない動作の例外状況で発生することがあります。','Replace gettext strings that have original ID NULL with the correct original IDs'=>'オリジナル ID が NULL の gettext 文字列を正しいオリジナル ID に置き換える','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'一部の gettext 文字列のオリジナル ID が誤って NULL に設定され、翻訳エディターで問題が発生するエッジケースを修正します。<br>この操作は、trp_gettext_* テーブル内のオリジナル ID を修正します。<br>翻訳エディターで緑の鉛筆アイコンをクリックしても左サイドバーに gettext 文字列が表示されない問題が発生した場合のみ、このオプションをチェックしてください。<br>それ以外の場合は、負荷が高いためこのオプションのチェックは外したままにしてください。','Optimize Database'=>'データベースを最適化','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'TranslatePress のテーブルを更新しています。このウィンドウを開いたままにしてください。','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'非アクティブな言語は管理者に対しては引き続き表示され、アクティブな状態になります。他のユーザーに対しては、言語スイッチャーに表示されず、アクセスすることもできません。','unknown'=>'不明','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Extra Languages アドオン</strong>には、TranslatePress バージョン %1$s 以上が必要です。現在お使いのバージョンは %2$s です。この機能を有効にするには、TranslatePress を更新してください。','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'<strong>TranslatePress - Multilingual</strong> 2.8.4 が有効だった間に行われた自動および手動の slug 翻訳の変更は、そのバージョンの問題により削除する必要がありました。そのバージョンより前の slug 翻訳はすべて現在も使用されています。ご理解のほどよろしくお願いいたします！','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'どうしても必要な場合、削除された翻訳は trp_slug_original_obsolete および trp_slug_translation_obsolete テーブルにあります。','View Docs'=>'ドキュメントを表示','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'各言語に異なるドメインまたはサブドメインを割り当てます。訪問者がこれらのドメインにアクセスすると、TranslatePress はリダイレクトせずに直接適切な言語翻訳を読み込みます。','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'例: 英語は %1$s、スペイン語は %2$s、フランス語は %3$s。','Before enabling:'=>'有効にする前:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'ドメインが登録済みで、サーバーに向けられており、SSL証明書が設定されていることを確認してください。','Domain'=>'ドメイン','Map this language to a different domain or sub-domain.'=>'この言語を別のドメインまたはサブドメインにマッピングします。','https://example.com'=>'https://example.com','Prefill with current domain'=>'現在のドメインで事前入力','Check DNS'=>'DNSを確認','Checking DNS...'=>'DNSを確認中…','DNS is correctly configured!'=>'DNSが正しく設定されています！','DNS check failed. Please verify your domain configuration.'=>'DNSの確認に失敗しました。ドメイン設定を確認してください。','This domain is already assigned to another language.'=>'このドメインはすでに別の言語に割り当てられています。','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Different Domain per Language アドオン</strong>には、TranslatePress バージョン %1$s 以降が必要です。現在のバージョンは %2$s です。この機能を有効にするには、TranslatePress をアップデートしてください。','Note: This option is disabled when Different Domain for Language addon is active.'=>'注: Different Domain for Language アドオンが有効な場合、このオプションは無効になります。','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: ドメインマッピングが有効な場合、ドメインは必須です。空のドメインが設定されている言語のトグルは無効化されました。','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: 同じドメインを複数の言語に割り当てることはできません。重複するドメインのトグルは無効化されました。','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: 言語ドメインをメインサイトの URL と同じにすることはできません。一致するドメインのトグルは無効化されました。','Please enter a domain.'=>'ドメインを入力してください。','Invalid domain format.'=>'無効なドメイン形式です。','Could not reach domain: %s'=>'ドメインに到達できません: %s','Domain returned HTTP status %d.'=>'ドメインが HTTP ステータス %d を返しました。','Domain is reachable!'=>'ドメインに到達できます！','Limit this menu item to the following languages'=>'このメニュー項目を以下の言語に限定する','Date format'=>'日付形式','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'翻訳された各言語ごとに日付形式をカスタマイズします。<br/>デフォルトのWP設定を使用するには空のままにするか、詳細情報は<a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">こちら</a>をご覧ください。','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'既存の TranslatePress 言語を編集するには、言語コードを入力し、上書きしたい列（例: 言語名、フラグ）のみを入力してください。<br>新しいカスタム言語も追加できます。これらは一般設定のすべての言語リストで利用可能になり、そこで URL slug を編集できます。','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'カスタムフラグの場合は、まずメディアライブラリに画像をアップロードしてから、URLを貼り付けてください。<br>カスタム言語の変更または削除は、翻訳とサイトのURLに影響を与えます。<br>言語コードとISOコードには、英字、数字、「-」と「_」のみを含める必要があります。<br>ISOコードは<a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a>および<a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>で確認できます。','Language code'=>'言語コード','Language name'=>'言語名','Native name'=>'ネイティブ名','ISO Code'=>'ISOコード','Flag URL'=>'フラグURL','Text RTL'=>'RTLテキスト','Custom language'=>'カスタム言語','Disable dynamic translation'=>'動的翻訳を無効化','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'JavaScript を使用して動的に表示される文字列の検出を無効にします。<br/>サーバーサイドの AJAX 呼び出しで読み込まれた文字列は引き続き翻訳されます。','Disable translation for gettext strings'=>'gettext 文字列の翻訳を無効化','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Gettext 文字列は、テーマとプラグインによって出力される文字列です。<br>これらの文字列がすでに .po/.mo 翻訳ファイルシステムを使用して翻訳されている場合、TranslatePress を通じて翻訳する必要がない場合があります。<br>このオプションを有効にすると、特定のケースでサイトのページ読み込みパフォーマンスが向上する可能性があります。欠点は、これらの文字列の gettext 翻訳を TranslatePress を使用して編集できなくなり、自動翻訳のメリットも受けられなくなることです。','Gettext Strings translation is disabled'=>'Gettext 文字列の翻訳が無効化されています','To enable it go to '=>'有効化するには ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->詳細設定->デバッグ->Gettext 文字列の翻訳を無効化',' and uncheck the Checkbox.'=>' のチェックボックスを外してください。','Dismiss'=>'閉じる','Exclude translated links from sitemap'=>'翻訳されたリンクをサイトマップから除外する','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'SEO プラグインが生成する sitemaps に翻訳されたリンクを含めないでください。<br/><a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack アドオン</a> のインストールと有効化が必要です。','Disable post container tags for post title'=>'投稿タイトルのコンテナタグを無効化','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'翻訳言語での投稿タイトルの検索インデックス登録を無効化します。<br/>投稿のタイトルが HTML を許可せず、ページが崩れる場合に便利です。','Disable post container tags for post content'=>'投稿コンテンツのコンテナタグを無効化','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'翻訳言語での投稿コンテンツの検索インデックス登録を無効化します。<br/>投稿のコンテンツが HTML を許可せず、ページが崩れる場合に便利です。','Do not translate certain paths'=>'特定のパスを翻訳しない','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'翻訳可能なパスを選択してください。パスの末尾にワイルドカードを使用できます。<br>例えば、https://example.com/some/path を除外するには、/some/path/ または /some/* のルールを使用できます。<br>各ルールは1行ずつ入力してください。ホームページを除外するには {home} を使用してください。','Exclude Paths From Translation'=>'翻訳からパスを除外','Translate Only Certain Paths'=>'特定のパスのみ翻訳','Enable the hreflang x-default tag for language:'=>'hreflang x-default タグを有効にする言語:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'言語全体に対して hreflang="x-default" を有効にします。詳細はドキュメントを参照してください。','Translate numbers and numerals'=>'数字と数詞の翻訳','Enable translation of numbers ( e.g. phone numbers)'=>'数字の翻訳を有効にする（例: 電話番号）','Selector'=>'セレクタ','Exclude from dynamic translation'=>'動的翻訳から除外','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'これらのセレクターに一致する HTML ノード内にある文字列を動的に翻訳しないようにします。<br>これらのセレクターに一致する HTML ノードのすべての子要素を、JavaScript を使用した翻訳から除外します。<br/>これらの文字列は、可能な場合はサーバー側で引き続き翻訳されます。','Gettext String'=>'Gettext 文字列','Exclude Gettext Strings'=>'Gettext 文字列を除外','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'これらの文字列が TranslatePress によって Gettext 文字列として翻訳されないように除外します。ドメインを空のままにすると、すべての Gettext 文字列が対象となります。<br/>po/mo ファイルを通じて引き続き翻訳できます。','Exclude selectors only from automatic translation'=>'セレクターを自動翻訳からのみ除外する','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'これらのセレクターに一致する HTML ノード内にある文字列を自動翻訳しないようにします。<br>これらのセレクターに一致する HTML ノードのすべての子要素を、自動翻訳から除外します。<br>これらの文字列の手動翻訳は引き続き可能です。','Exclude selectors from translation'=>'セレクターを翻訳から除外する','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'これらのセレクターに一致する HTML ノード内にある文字列を翻訳しないようにします。<br>これらのセレクターに一致する HTML ノードのすべての子要素を、翻訳から除外します。<br>これらの文字列は手動および自動のいずれでも翻訳できません。','String'=>'文字列','Exclude strings from automatic translation'=>'文字列を自動翻訳から除外','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'これらの文字列（例: 名前、技術用語など）を自動翻訳しないようにします。<br>これらの文字列を含む段落は、指定した部分を除いて引き続き翻訳されます。','Fix broken HTML'=>'壊れた HTML を修正する','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'翻訳されたページ上の壊れたまたは欠落している HTML を修正するための一般的な試みです。<br/>','Force slash at end of home url:'=>'ホーム URL の末尾にスラッシュを強制する:','Ads a slash at the end of the home_url() function'=>'home_url() 関数の末尾にスラッシュを追加します','Show Both (recommended)'=>'両方を表示する（推奨）','Remove Country Locale'=>'国ロケールを削除する','Remove Region Independent Locale'=>'地域に依存しないロケールを削除する','Remove duplicate hreflang'=>'重複した hreflang を削除する','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'ウェブサイトに表示する hreflang タグを選択してください。<br/>Google の<a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">ドキュメント</a>で示されているように、両方の hreflang タグを表示することをおすすめします。<br/>同じ言語で複数の国ロケールがある場合（例: 英語（英国）と英語（米国））に国ロケールを削除すると、その言語の地域ロケールのうち 1 つへのリンクのみを含む 1 つの hreflang タグが表示されます。','Default (example: en-US, fr-CA, etc.)'=>'デフォルト（例: en-US、fr-CA など）','Regional (example: en, fr, es, etc.)'=>'地域（例: en、fr、es など）','HTML Lang Attribute Format'=>'HTML Lang 属性の形式','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'HTMLタグのlang属性を、国・地域を含む形式または含まない形式に変更します。<br>HTMLでは、lang属性（<html lang="en-US">）を使用してテキストコンテンツの言語を指定し、ブラウザーがコンテンツを正しく表示または処理できるようにする必要があります（例: ハイフネーション、スタイル設定、スペルチェックなど）。','Load legacy Language Switcher'=>'従来の言語切り替えを読み込む','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'フローティング、ショートコード、メニューのすべてのタイプの言語切り替えに適用されます。有効にすると、サイトは「一般設定」タブで設定された元の言語切り替えを使用するよう戻り、新しいカスタマイズ可能なバージョンを置き換えます。既存の言語切り替え設定は保存されたままですが、このオプションが有効な間は無視されます。','Load legacy SEO Pack Add-On'=>'従来のSEO Packアドオンを読み込む','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'新しい slug 書き換えへの移行で問題が発生している場合は、これを「はい」に設定して従来の方法を使用してください。<br>発生している問題について、<a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">サポートチケットを作成</a>してお知らせください。','Manual Translation Only'=>'手動翻訳のみ','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress は、ユーザーが翻訳ページにアクセスしたときに、積極的に文字列をスキャンしてデータベースに保存します。<br>この設定はこの機能を無効化し、翻訳エディター内でのみ翻訳と文字列の保存を許可します。<br>また、翻訳エディター外での機械翻訳も無効化し、翻訳エディターで閲覧したページのみを翻訳することで、文字数の消費をより適切に管理できます。','Open language switcher only on click'=>'クリック時のみ言語切り替えを開く','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'ホバーではなくクリックして言語切り替えショートコードを開きます。<br>クリック、画面の他の場所をクリック、またはEscキーを押すことで閉じます。これはショートコードの言語切り替えにのみ影響します。','Show opposite language in the language switcher'=>'言語切り替えに現在の言語ではなく他の言語を表示する','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'言語切り替えを、現在の言語ではなく他の利用可能な言語を表示するボタンに変換します。<br>デフォルトの言語と翻訳言語のちょうど2つがある場合にのみ動作します。<br>これはショートコードの言語切り替えとフローティング言語切り替えにも影響します。<br>メニューの言語切り替えでこれを実現するには、外観->メニュー->言語切り替えに移動し、「他の言語」を選択してください。','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">こちらをクリック</a>して、データベース最適化ツールにアクセスします。','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'重複した翻訳の削除、不要なデータの消去、およびメタデータの問題の修復に役立ちます。','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">こちら</a>で、TranslatePressに関連する最新5件のSQLエラーが存在する場合に確認できます。','Troubleshooting'=>'トラブルシューティング','Exclude Gettext strings'=>'Gettext 文字列を除外','Debug'=>'デバッグ','Custom languages'=>'カスタム言語','Miscellaneous options'=>'その他のオプション','Exclude strings & pages'=>'文字列とページを除外','Automatic Translation Memory'=>'自動翻訳メモリ','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'類似したテキストには同じ翻訳を適用します。文字列は95%の類似度が必要です。<br>タイプミスの修正や元のテキストの微調整時に、既存の翻訳が失われるのを防ぎます。 <br>非常に類似した元の文字列の翻訳が既に存在する場合、現在の元の文字列に自動的に適用されます。<br>翻訳ブロックの一部であるテキストを変更した場合、新しいテキストが翻訳ブロックに再度手動でマージされない限り機能しません。<br>各文字列は最低50文字必要です。','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'警告: この機能は、第2言語でのページ読み込み時間に悪影響を及ぼす可能性があります。データベースが大きい場合（例えば、ページや商品が多数あるウェブサイトなど）には特に顕著です。読み込みが遅くなる場合は、この機能を無効にして再度お試しください。','Fix missing dynamic content'=>'動的コンテンツの欠落を修正','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'JavaScriptを使用して挿入されたコンテンツの欠落を修正するのに役立つ場合があります。 <br> 翻訳リクエストが完了する前に、動的に挿入されたコンテンツをオリジナル言語で一瞬表示します。','Filter Gettext wrapping from post content and title'=>'投稿コンテンツとタイトルからGettextラッピングを除去','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'すべての更新済み投稿コンテンツと投稿タイトルから、#!trpst#trp-gettextなどのGettextラッピングを除去します。以前の投稿コンテンツには影響しません。<br/><strong>有効化する前にデータベースのバックアップを推奨します。</strong>','Filter Gettext wrapping from post meta'=>'投稿メタからGettextラッピングを除去','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'すべての更新済み投稿メタから、#!trpst#trp-gettextなどのGettextラッピングを除去します。以前の投稿メタには影響しません。<br/><strong>有効化する前にデータベースのバックアップを推奨します。</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Google Translate APIキー','Add your API Key here...'=>'APIキーをここに追加...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'<a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">このリンク</a>から、APIキーの設定方法、<strong>APIコストの管理</strong>、およびHTTPリファラ制限の設定方法をご確認ください。','Your HTTP referrer is: %s'=>'HTTPリファラ: %s','There was an error on the server processing your Google Translate key.'=>'Google Translateキーのサーバー処理中にエラーが発生しました。','There was an error with your Google Translate key.'=>'Google Translateキーでエラーが発生しました。','Please check your TranslatePress license key.'=>'TranslatePressライセンスキーをご確認ください。','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'このウェブサイトで有効なライセンスが検出されませんでした。','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'TranslatePress AIを使用した自動翻訳を有効にするには、無料アカウントを作成してライセンスキーを取得する必要があります。','Create your Free Account'=>'無料アカウントを作成',' or '=>' または ','Enter your license key'=>'ライセンスキーを入力',' Or %1$spurchase one here%2$s'=>' または %1$sこちらで購入%2$s','Your free account includes: '=>'無料アカウントの特典: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'TranslatePress Proでより多くのAIワードを取得し、すべてのAI機能をアンロックします。','You have a valid %s <strong>license</strong>.'=>'有効な%s <strong>ライセンス</strong>が登録されています。',' words remaining. '=>' 残りワード。 ','Recheck'=>'再チェック','Rechecking...'=>'再チェック中...','Done.'=>'完了。','Manage your license & quota on the %s'=>'%sでライセンスとクォータを管理','TranslatePress.com Account Page'=>'TranslatePress.com アカウントページ','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'ページslug、ページタイトル、説明、およびFacebookとTwitterのソーシャルグラフ情報のSEOサポート。HTMLのlang属性が適切に設定されます。','Enable Modules'=>'モジュールを有効化','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'アドオンモジュールを有効化して、TranslatePressを拡張し、翻訳サイトの機能を強化します。','More functionality with TranslatePress Pro.'=>'TranslatePress Proでさらに多くの機能を利用できます。','Already a Pro User?'=>'すでにProユーザーですか？','Activate License Key'=>'ライセンスキーを有効化','This add-on is not available on your current plan.'=>'このアドオンは現在のプランでは利用できません。','Continue'=>'続ける','The link you followed has expired. Please reload the page and try again.'=>'フォローしたリンクは期限切れです。ページを再読み込みして、もう一度お試しください。','A valid license is required to enable Automatic Translation.'=>'自動翻訳を有効にするには、有効なライセンスが必要です。','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'このURLではライセンスキーが無効になっています。<a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> サイトの管理 から再度有効化してください。','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>ライセンスキーが一致しません。</strong>入力されたライセンスは、インストールされているTranslatePressのバージョンと一致しません。</p><p>TranslatePressアカウントから、ライセンスに対応する正しいバージョンをインストールしているか確認してください。</p>','Automatically translate your website using TranslatePress AI.'=>'TranslatePress AIを使用して、サイトを自動翻訳します。','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'TranslatePress AIを使用した自動翻訳を有効にするには、ライセンスキーを','your account.'=>'アカウントから入力してください。','Skip and continue with manual translation »'=>'スキップして手動翻訳で続ける »','Get Your Free TranslatePress AI License'=>'無料のTranslatePress AIライセンスを取得','Generate License'=>'ライセンスを生成','Creating a free account includes: '=>'無料アカウントの作成には以下が含まれます: ','Are you a TranslatePress PRO user?'=>'TranslatePress Proのユーザーですか？','Install & Activate your pro plugin.'=>'Proプラグインをインストール&有効化してください。','Skip this step'=>'このステップをスキップ','The email address you added is incorrect.'=>'入力されたメールアドレスが正しくありません。','Setup Complete'=>'セットアップ完了','You\'re ready to start translating!'=>'翻訳を開始する準備ができました！','You have successfully set up TranslatePress for your website.'=>'TranslatePressのセットアップが正常に完了しました。','Receive '=>'受け取る ','Yes, send me multilingual growth tips.'=>'はい、多言語成長のヒントを受け取ります。','Start translating'=>'翻訳を開始','Sign Up and Start translating'=>'サインアップして翻訳を開始','Please upload a TranslatePress Pro plugin file.'=>'TranslatePress Pro のプラグインファイルをアップロードしてください。','Upload error: '=>'アップロードエラー: ','Install failed: '=>'インストールに失敗しました: ','Plugin installed, but entry file not found. '=>'プラグインはインストールされましたが、エントリーファイルが見つかりませんでした。 ','Activation error: '=>'有効化エラー: ','Invalid plugin specified.'=>'無効なプラグインが指定されました。','Invalid action specified.'=>'無効なアクションが指定されました。','Plugin deactivation failed.'=>'プラグインの無効化に失敗しました。','Plugin activation failed: '=>'プラグインの有効化に失敗しました: ','First, install and activate TranslatePress Pro'=>'まず、TranslatePress Pro をインストールして有効化してください','Please upload the TranslatePress PRO zip archive from your'=>'TranslatePress PRO の zip アーカイブをアップロードしてください。','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'インストールして有効化','Installed Pro versions'=>'インストール済みの Pro バージョン','« Go back'=>'« 戻る','Activate License »'=>'ライセンスを有効化 »','You are trying to add an invalid additional language. Please select a valid option.'=>'無効な追加言語を追加しようとしています。有効なオプションを選択してください。','Please add an additional language.'=>'追加言語を追加してください。','You are trying to add an invalid default language. Please select a valid option.'=>'無効なデフォルト言語を追加しようとしています。有効なオプションを選択してください。','You need to select a default language.'=>'デフォルト言語を選択する必要があります。','Configure Site Languages'=>'サイト言語の設定','Select the default and additional languages for your website.'=>'サイトのデフォルト言語と追加言語を選択してください。','You can edit your site languages at any point.'=>'サイト言語はいつでも編集できます。','Additional Language'=>'追加言語','Choose a secondary language...'=>'第2言語を選択...','Add Language'=>'言語を追加','Choose a language...'=>'言語を選択...','Add more than two languages with TranslatePress Pro.'=>'TranslatePress Pro で2つを超える言語を追加できます。','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'この URL でライセンスキーが無効になっています。<a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> サイト管理 から再有効化してください。','Add your License Key'=>'ライセンスキーを追加','Add your License Key to unlock all premium features. Find the License Key in your'=>'すべてのプレミアム機能を有効化するには、ライセンスキーを追加してください。ライセンスキーは、お客様の','Your license is valid and active.'=>'ライセンスは有効でアクティブです。','« Go Back'=>'« 戻る','Set up Language Switcher'=>'言語スイッチャーの設定','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'言語スイッチャーのスタイルを選択してください。プラグイン設定でさらに表示方法を見つけることができます。','Displays a small language drop-down across your website, in a corner of your choosing.'=>'サイト内の選択した隅に、小さな言語ドロップダウンを表示します。','Switcher Location'=>'スイッチャーの位置','Apply a Template'=>'テンプレートを適用','You can customize the design later'=>'後でデザインをカスタマイズできます','Default Template'=>'デフォルトテンプレート','Dark Template'=>'ダークテンプレート','Border Template'=>'ボーダーテンプレート','Border'=>'ボーダー','Transparent Template'=>'透明テンプレート','Transparent'=>'透明','Welcome to TranslatePress'=>'TranslatePress へようこそ','Quick guided setup to configure TranslatePress in no time!'=>'TranslatePress をすぐに設定できるガイド付きクイックセットアップです！','It takes less than a minute.'=>'1分もかかりません。','Scanning item %1$d of %2$d...'=>'%2$d 件中 %1$d 件目をスキャン中...','Manually translated'=>'手動翻訳','Automatically translated'=>'自動翻訳','Not translated'=>'未翻訳','Bulk Actions'=>'一括操作','Delete entries'=>'エントリーを削除','Edit'=>'編集','Delete'=>'削除','Filter'=>'絞り込み','Clear filters'=>'フィルターをクリア','Add New'=>'新規追加','Rescan plugins and theme for strings'=>'プラグインとテーマの文字列を再スキャン','Scanning plugins and theme for strings...'=>'プラグインとテーマの文字列をスキャン中...','Plugins and theme scan is complete'=>'プラグインとテーマのスキャンが完了しました','Plugins and theme scan did not finish due to an error'=>'プラグインとテーマのスキャンがエラーで完了しませんでした','Import / Export'=>'インポート / エクスポート','items'=>'項目','See More'=>'もっと見る','See Less'=>'表示を減らす','Apply'=>'適用','No strings match your query.'=>'クエリに一致する文字列はありません。','Try to rescan plugins and theme for strings.'=>'プラグインとテーマの文字列を再スキャンしてみてください。','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'結果の読み込み中にエラーが発生しました。おそらくログアウトしました。ページを再読み込みしますか？','found in translation'=>'翻訳で見つかりました','Select All'=>'すべて選択','Select Visible'=>'表示されている項目を選択','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'フィルターに一致するすべての文字列に対してこのアクションを実行しようとしています。表示されているチェック済みの文字列だけではありません。表示されている文字列のみに対してアクションを実行するには、テーブルヘッダーのドロップダウンから「表示されている項目を選択」をクリックしてください。','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'表示されている文字列のみに対してこのアクションを実行しようとしています。フィルターに一致するすべての文字列に対してアクションを実行するには、テーブルヘッダーのドロップダウンから「すべて選択」をクリックしてください。','To continue please type the word:'=>'続行するには、次の単語を入力してください:','The word typed was incorrect. Action was cancelled.'=>'入力された単語が正しくありませんでした。アクションはキャンセルされました。','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'警告: このアクションは元に戻せません。文字列を削除すると、現在の翻訳が削除されます。元の文字列は、TranslatePressが検出した後にこのインターフェースに再度表示されます。このアクションは、文字列を翻訳対象から除外することと同等ではありません。','%d original entries and their translations were deleted.'=>'%d 件の元のエントリとその翻訳が削除されました。','Navigate to next page'=>'次のページへ移動','Navigate to previous page'=>'前のページへ移動','Navigate to first page'=>'最初のページへ移動','Navigate to last page'=>'最後のページへ移動','Type a page number to navigate to'=>'移動先のページ番号を入力','Incorrect page number. Type a page number between 1 and total number of pages'=>'ページ番号が正しくありません。1 から総ページ数までのページ番号を入力してください。','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'選択されたフィルターを適用しながら、入力したキーワードを含む元の文字列と翻訳済み文字列を検索します。完全一致で検索するには文字列を引用符で囲んでください: 「文字列」','Filter strings according to selected translation status, filters and keywords and selected filters'=>'選択された翻訳ステータス、フィルター、キーワード、および選択されたフィルターに基づいて文字列をフィルタリングします。','Removes selected filters'=>'選択したフィルタを削除','See options for selecting all strings'=>'すべての文字列を選択するオプションを表示','Click to sort strings by this column'=>'この列で文字列を並べ替えるにはクリックしてください','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'翻訳ステータスフィルタが適用される言語。翻訳ステータスをすべての言語に適用するには未選択のままにしてください。','Search'=>'検索','Slugs that are not found in either one of the other categories.'=>'他のいずれのカテゴリにも見つからないslug。','Plugins and Theme String Translation'=>'プラグインとテーマの文字列翻訳','Gettext'=>'Gettext','Search Gettext Strings'=>'Gettext文字列の検索','ID'=>'ID','Original String'=>'原文','Translation'=>'翻訳','Filter by domain'=>'ドメインで絞り込む','Filter by type'=>'タイプで絞り込む','Email text'=>'メールテキスト','Emails String Translation'=>'メール文字列の翻訳','Emails'=>'メール','Search Email Strings'=>'メール文字列を検索','User Inputted String Translation'=>'ユーザー入力文字列の翻訳','Regular'=>'通常','Search Regular Strings'=>'通常の文字列を検索','Filter by Translation Block'=>'翻訳ブロックで絞り込む','URL Slugs Translation'=>'URL slugの翻訳','String Translation Editor'=>'文字列翻訳エディター','TranslatePress has detected and cleaned up some failed translation entries in your database following %1$san isolated incident%2$s. No further action is required.'=>'TranslatePress は、%1$s単発的なインシデント%2$sの後、データベース内のいくつかの失敗した翻訳エントリを検出してクリーンアップしました。これ以上の操作は必要ありません。','Post Slug'=>'投稿slug','Invalid language code'=>'無効な言語コード','First by browser language, then IP address (recommended)'=>'まずブラウザーの言語、次にIPアドレス（推奨）','First by IP address, then by browser language'=>'まずIPアドレス、次にブラウザーの言語','Only by browser language'=>'ブラウザの言語のみで判定','Only by IP address'=>'IPアドレスのみで判定','A popup appears asking the user if they want to be redirected'=>'リダイレクトするかどうかユーザーに尋ねるポップアップが表示されます','Redirect directly (*not recommended)'=>'直接リダイレクト (*非推奨)','Pop-up window over the content'=>'コンテンツ上のポップアップウィンドウ','Hello bar before the content'=>'コンテンツ前の Hello bar','WARNING. Cannot determine your language preference based on your current IP.<br>This is most likely because the website is on a local environment.'=>'WARNING. 現在の IP アドレスから言語設定を判定できません。<br>おそらく、Web サイトがローカル環境にあるためです。','Go to <a href="%s" target="_self">Advanced</a> tab to change this feature\'s settings'=>'この機能の設定を変更するには、<a href="%s" target="_self">詳細設定</a>タブに移動してください。','User Language Detection Method'=>'ユーザーの言語判定方法','Select how the language should be detected for first time visitors.<br>The visitor\'s last displayed language will be remembered through cookies.'=>'初回訪問者の言語判定方法を選択してください。<br>訪問者に最後に表示された言語は Cookie で記憶されます。','User Notification Popup'=>'ユーザー通知ポップアップ','A popup appears asking the user if they want to be redirected.'=>'リダイレクトするかどうかユーザーに尋ねるポップアップが表示されます。','Popup Type'=>'ポップアップの種類','Popup Text'=>'ポップアップのテキスト','The same text is displayed in all languages. <br>A selecting language switcher will be appended to the pop-up. The detected language is pre-selected.'=>'すべての言語で同じテキストが表示されます。<br>ポップアップには言語切り替えセレクターが追加され、検出された言語が事前に選択されています。','Button Text'=>'ボタンのテキスト','Write the text you wish to appear on the button..'=>'ボタンに表示するテキストを入力してください。','Close Button Text'=>'閉じるボタンのテキスト','Write the text you wish to appear on the close button. Leave empty for just the close button.'=>'閉じるボタンに表示するテキストを入力してください。空欄にすると、閉じるボタンのみが表示されます。','Bad request. There was an error accessing the DeepL API.'=>'不正なリクエストです。DeepL API へのアクセス中にエラーが発生しました。','The API key entered is invalid.'=>'入力されたAPIキーは無効です。','The API resource could not be found.'=>'APIリソースが見つかりませんでした。','The request size is too large.'=>'リクエストサイズが大きすぎます。','The request is too long.'=>'リクエストが長すぎます。','Too many requests. Please try again later.'=>'リクエストが多すぎます。しばらくしてからもう一度お試しください。','Your translation quota has been reached.'=>'翻訳クォータに達しました。','We could not process your request. Please try again later.'=>'リクエストを処理できませんでした。しばらくしてからもう一度お試しください。','There is an error on the DeepL service and your request could not be processed.'=>'DeepLサービスでエラーが発生し、リクエストを処理できませんでした。','DeepL API Type'=>'DeepL API の種類','Pro'=>'Pro','Free'=>'Free','Select the type of DeepL API you want to use.'=>'使用するDeepL APIの種類を選択してください。','DeepL API Key'=>'DeepL APIキー','Visit <a href="%s" target="_blank">this link</a> to see how you can set up an API key and control API costs.'=>'APIキーの設定方法とAPIコストの管理については、<a href="%s" target="_blank">このリンク</a>をご覧ください。','Translator'=>'翻訳者',' TranslatePress Settings'=>' TranslatePress の設定','Allow this user to translate the website.'=>'このユーザーがウェブサイトを翻訳できるようにします。','(inactive)'=>'(無効)','Taxonomy Slugs'=>'タクソノミーslug','Search Taxonomy Slugs'=>'タクソノミーslugを検索','Taxonomy Slug'=>'タクソノミーslug','Term Slugs'=>'タームslug','Search Term Slugs'=>'タームslugを検索','Term Slug'=>'タームslug','Taxonomy'=>'タクソノミー','Filter by Taxonomy'=>'タクソノミーで絞り込む','Post Slugs'=>'投稿slug','Search Post Slugs'=>'投稿slugを検索','Post ID'=>'投稿ID','Post Type'=>'投稿タイプ','Filter by Post Type'=>'投稿タイプで絞り込む','Published'=>'公開済み','Any Post Status'=>'すべての投稿ステータス','Post Type Base Slugs'=>'投稿タイプベースのslug','Post Type Base Slug'=>'投稿タイプベースのslug','Search Post Type Base Slugs'=>'投稿タイプベースのslugを検索','WooCommerce Slugs'=>'WooCommerceのslug','WooCommerce Slug'=>'WooCommerceのslug','Search WooCommerce Slugs'=>'WooCommerceのslugを検索','Other Slugs'=>'その他のslug','Search Other Slugs'=>'その他のslugを検索','Verbiage for the DeepL Pro Add-onTranslatePress Pro Add-on'=>'TranslatePress Pro Add-on','Verbiage for the DeepL Pro Add-onAddons tab'=>'アドオンタブ','page 1 of 3of'=>'/','Untranslated in this languagein'=>'で']];